42		pattern := "^sha256[:-][0-9a-fA-F]{64}$"
43		re := regexp.MustCompile(pattern)
44	
45		if digest != "" && !re.MatchString(digest) {
46			return "", ErrInvalidDigestFormat
47		}
48	
49		digest = strings.ReplaceAll(digest, ":", "-")
50		path := filepath.Join(envconfig.Models(), "blobs", digest)
51		dirPath := filepath.Dir(path)
52		if digest == "" {
53			dirPath = path
54		}
55	
56		if err := os.MkdirAll(dirPath, 0o755); err != nil {
57			return "", fmt.Errorf("%w: ensure path elements are traversable", err)
58		}
59	
60		return path, nil
61	}
62	
63	// PruneDirectory removes empty directories recursively.
64	func PruneDirectory(path string) error {
65		info, err := os.Lstat(path)
66		if err != nil {
67			return err
68		}
69	
70		if info.IsDir() && info.Mode()&os.ModeSymlink == 0 {
71			entries, err := os.ReadDir(path)
72			if err != nil {
73				return err
74			}
75	
76			for _, entry := range entries {
77				if err := PruneDirectory(filepath.Join(path, entry.Name())); err != nil {
78					return err
79				}
80			}
81	
82			entries, err = os.ReadDir(path)
83			if err != nil {
84				return err
85			}
86	
87			if len(entries) > 0 {
88				return nil
89			}
90	
91			return os.Remove(path)
92		}
93	
94		return nil
95	}
