88	// Name is a structured representation of a model name string, as defined by
89	// [ParseNameNoDefaults].
90	//
91	// It is not guaranteed to be valid. Use [Name.IsValid] to check if the name
92	// is valid.
93	type Name struct {
94		Host           string
95		Namespace      string
96		Model          string
97		Tag            string
98		ProtocolScheme string
99	}
100	
101	// ParseName parses and assembles a Name from a name string. The
102	// format of a valid name string is:
103	//
104	//	  s:
105	//		  { host } "/" { namespace } "/" { model } ":" { tag } "@" { digest }
106	//		  { host } "/" { namespace } "/" { model } ":" { tag }
107	//		  { host } "/" { namespace } "/" { model } "@" { digest }
108	//		  { host } "/" { namespace } "/" { model }
109	//		  { namespace } "/" { model } ":" { tag } "@" { digest }
110	//		  { namespace } "/" { model } ":" { tag }
111	//		  { namespace } "/" { model } "@" { digest }
112	//		  { namespace } "/" { model }
113	//		  { model } ":" { tag } "@" { digest }
114	//		  { model } ":" { tag }
115	//		  { model } "@" { digest }
116	//		  { model }
117	//		  "@" { digest }
118	//	  host:
119	//	      pattern: { alphanum | "_" } { alphanum | "-" | "_" | "." | ":" }*
120	//	      length:  [1, 350]
121	//	  namespace:
122	//	      pattern: { alphanum | "_" } { alphanum | "-" | "_" }*
123	//	      length:  [1, 80]
124	//	  model:
125	//	      pattern: { alphanum | "_" } { alphanum | "-" | "_" | "." }*
126	//	      length:  [1, 80]
127	//	  tag:
128	//	      pattern: { alphanum | "_" } { alphanum | "-" | "_" | "." }*
129	//	      length:  [1, 80]
130	//	  digest:
131	//	      pattern: { alphanum | "_" } { alphanum | "-" | ":" }*
132	//	      length:  [1, 80]
133	//
134	// Most users should use [ParseName] instead, unless need to support
135	// different defaults than DefaultName.
136	//
137	// The name returned is not guaranteed to be valid. If it is not valid, the
138	// field values are left in an undefined state. Use [Name.IsValid] to check
139	// if the name is valid.
140	func ParseName(s string) Name {
141		return Merge(ParseNameBare(s), DefaultName())
142	}
143	
144	// ParseNameBare parses s as a name string and returns a Name. No merge with
145	// [DefaultName] is performed.
146	func ParseNameBare(s string) Name {
147		var n Name
148		var promised bool
149	
150		// "/" is an illegal tag character, so we can use it to split the host
151		if strings.LastIndex(s, ":") > strings.LastIndex(s, "/") {
152			s, n.Tag, _ = cutPromised(s, ":")
153		}
154	
155		s, n.Model, promised = cutPromised(s, "/")
156		if !promised {
157			n.Model = s
158			return n
159		}
160	
161		s, n.Namespace, promised = cutPromised(s, "/")
162		if !promised {
163			n.Namespace = s
164			return n
165		}
166	
167		scheme, host, ok := strings.Cut(s, "://")
168		if ok {
169			n.ProtocolScheme = scheme
170		} else {
171			host = scheme
172		}
173		n.Host = host
174	
175		return n
176	}
177	
178	// ParseNameFromFilepath parses a 4-part filepath as a Name. The parts are
179	// expected to be in the form:
180	//
181	// { host } "/" { namespace } "/" { model } "/" { tag }
182	func ParseNameFromFilepath(s string) (n Name) {
183		parts := strings.Split(s, string(filepath.Separator))
184		if len(parts) != 4 {
185			return Name{}
186		}
187	
188		n.Host = parts[0]
189		n.Namespace = parts[1]
190		n.Model = parts[2]
191		n.Tag = parts[3]
192		if !n.IsFullyQualified() {
193			return Name{}
194		}
195	
196		return n
197	}
198	
199	// Merge merges the host, namespace, tag, and protocol scheme parts of the two names,
200	// preferring the non-empty parts of a.
201	func Merge(a, b Name) Name {
202		a.Host = cmp.Or(a.Host, b.Host)
203		a.Namespace = cmp.Or(a.Namespace, b.Namespace)
204		a.Tag = cmp.Or(a.Tag, b.Tag)
205		a.ProtocolScheme = cmp.Or(a.ProtocolScheme, b.ProtocolScheme)
206		return a
207	}
208	
209	// String returns the name string, in the format that [ParseNameNoDefaults]
210	// accepts as valid, if [Name.IsValid] reports true; otherwise the empty
211	// string is returned.
212	func (n Name) String() string {
213		var b strings.Builder
214		if n.Host != "" {
215			b.WriteString(n.Host)
216			b.WriteByte('/')
217		}
218		if n.Namespace != "" {
219			b.WriteString(n.Namespace)
220			b.WriteByte('/')
221		}
222		b.WriteString(n.Model)
223		if n.Tag != "" {
224			b.WriteByte(':')
225			b.WriteString(n.Tag)
226		}
227		return b.String()
228	}
229	
230	// DisplayShortest returns a short string version of the name.
231	func (n Name) DisplayShortest() string {
232		var sb strings.Builder
233	
234		if !strings.EqualFold(n.Host, defaultHost) {
235			sb.WriteString(n.Host)
236			sb.WriteByte('/')
237			sb.WriteString(n.Namespace)
238			sb.WriteByte('/')
239		} else if !strings.EqualFold(n.Namespace, defaultNamespace) {
240			sb.WriteString(n.Namespace)
241			sb.WriteByte('/')
242		}
243	
244		// always include model and tag
245		sb.WriteString(n.Model)
246		sb.WriteString(":")
247		sb.WriteString(n.Tag)
248		return sb.String()
249	}
