42	// serverError is like ollama.Error, but with a Status field for the HTTP
43	// response code. We want to avoid adding that field to ollama.Error because it
44	// would always be 0 to clients (we don't want to leak the status code in
45	// errors), and so it would be confusing to have a field that is always 0.
46	type serverError struct {
47		Status int `json:"-"`
48	
49		// TODO(bmizerany): Decide if we want to keep this and maybe
50		// bring back later.
51		Code string `json:"code"`
52	
53		Message string `json:"error"`
54	}
