56	func (e serverError) Error() string {
57		return e.Message
58	}
59	
60	// Common API errors
61	var (
62		errMethodNotAllowed = &serverError{405, "method_not_allowed", "method not allowed"}
63		errNotFound         = &serverError{404, "not_found", "not found"}
64		errModelNotFound    = &serverError{404, "not_found", "model not found"}
65		errInternalError    = &serverError{500, "internal_error", "internal server error"}
66	)
