259	func (s *Local) handlePull(w http.ResponseWriter, r *http.Request) error {
260		if r.Method != "POST" {
261			return errMethodNotAllowed
262		}
263	
264		p, err := decodeUserJSON[*params](r.Body)
265		if err != nil {
266			return err
267		}
268	
269		enc := json.NewEncoder(w)
270		if !p.stream() {
271			if err := s.Client.Pull(r.Context(), p.model()); err != nil {
272				if errors.Is(err, ollama.ErrModelNotFound) {
273					return errModelNotFound
274				}
275				return err
276			}
277			enc.Encode(progressUpdateJSON{Status: "success"})
278			return nil
279		}
280	
281		var mu sync.Mutex
282		var progress []progressUpdateJSON
283		flushProgress := func() {
284			mu.Lock()
285			progress := slices.Clone(progress) // make a copy and release lock before encoding to the wire
286			mu.Unlock()
287			for _, p := range progress {
288				enc.Encode(p)
289			}
290			fl, _ := w.(http.Flusher)
291			if fl != nil {
292				fl.Flush()
293			}
294		}
295	
296		t := time.NewTicker(1<<63 - 1) // "unstarted" timer
297		start := sync.OnceFunc(func() {
298			flushProgress() // flush initial state
299			t.Reset(100 * time.Millisecond)
300		})
301		ctx := ollama.WithTrace(r.Context(), &ollama.Trace{
302			Update: func(l *ollama.Layer, n int64, err error) {
303				if err != nil && !errors.Is(err, ollama.ErrCached) {
304					s.Logger.Error("pulling", "model", p.model(), "error", err)
305					return
306				}
307	
308				func() {
309					mu.Lock()
310					defer mu.Unlock()
311					for i, p := range progress {
312						if p.Digest == l.Digest {
313							progress[i].Completed = n
314							return
315						}
316					}
317					progress = append(progress, progressUpdateJSON{
318						Digest: l.Digest,
319						Total:  l.Size,
320					})
321				}()
322	
323				// Block flushing progress updates until every
324				// layer is accounted for. Clients depend on a
325				// complete model size to calculate progress
326				// correctly; if they use an incomplete total,
327				// progress indicators would erratically jump
328				// as new layers are registered.
329				start()
330			},
331		})
332	
333		done := make(chan error, 1)
334		go func() (err error) {
335			defer func() { done <- err }()
336			for _, err := range backoff.Loop(ctx, 3*time.Second) {
337				if err != nil {
338					return err
339				}
340				err := s.Client.Pull(ctx, p.model())
341				if canRetry(err) {
342					continue
343				}
344				return err
345			}
346			return nil
347		}()
348	
349		enc.Encode(progressUpdateJSON{Status: "pulling manifest"})
350		for {
351			select {
352			case <-t.C:
353				flushProgress()
354			case err := <-done:
355				flushProgress()
356				if err != nil {
357					if errors.Is(err, ollama.ErrModelNotFound) {
358						return &serverError{
359							Status:  404,
360							Code:    "not_found",
361							Message: fmt.Sprintf("model %q not found", p.model()),
362						}
363					} else {
364						return err
365					}
366				}
367	
368				// Emulate old client pull progress (for now):
369				enc.Encode(progressUpdateJSON{Status: "verifying sha256 digest"})
370				enc.Encode(progressUpdateJSON{Status: "writing manifest"})
371				enc.Encode(progressUpdateJSON{Status: "success"})
372				return nil
373			}
374		}
375	}
